require"UI.UIBase"require"UI.UIBlock"UI_Highlight=UIBase:Inherit()function UI_Highlight:OnCreate()UI_Highlight.Inst=self;self:Build()end;function UI_Highlight:OnShow(a,b)self:SetLocking(true)self.transform.gameObject:SetActive(true)self.closeCallback=b.closeCallback;self:MakeBadgeData()self:RefreshUI()TimeMgr.Delay(1.0,function()a()self:SetLocking(false)end)end;function UI_Highlight:OnClose(a)if self.locking then return end;self:SetLocking(true)TimeMgr.Delay(0.1,function()self:SetLocking(false)self.transform.gameObject:SetActive(false)for c=1,5 do self.badges[c].transform.gameObject:SetActive(false)self.badges[c].root.gameObject:SetActive(false)end;if self.closeCallback then self.closeCallback()end;a()end)end;function UI_Highlight:SetLocking(d)self.locking=d;self.click_mask.gameObject:SetActive(d)end;function UI_Highlight:Build()self.badges={}for c=1,5 do local e={}e.transform=self.badge_root:Find("badge"..c)e.root=e.transform:Find("badge")e.img_icon=e.root:Find("icon"):GetComponent(typeof(UnityEngine.UI.Image))e.txt_name=e.root:Find("name"):GetComponent(typeof(UnityEngine.UI.Text))e.txt_point=e.root:Find("point"):GetComponent(typeof(UnityEngine.UI.Text))e.btn=e.img_icon.transform:GetComponent(typeof(UnityEngine.UI.Button))e.btn.onClick:AddListener(function()self:OpenPopup(c)end)table.insert(self.badges,e)if GameMgr.Inst.prefer_language=='en'then e.txt_name.fontSize=22 end end;self.anim_highlight=self.anim_highlight_root:GetComponent(typeof(UnityEngine.Animator))end;function UI_Highlight:MakeBadgeData()self.badge_info={}self.badge_index={}local f=ExcelMgr.GetTable("achievement","badge_group")for g,h in pairs(DesktopMgr.Inst.badge_info)do local i=ExcelMgr.GetData("achievement","badge",h.id)if i and i.id then local j;if f and#f>0 then for g,d in pairs(f)do if d.badge_id and(d.badge_id[1]==i.id or#d.badge_id>1 and d.badge_id[2]==i.id)then j=d;break end end end;if j and j.id then if self.badge_info[j.id]then self.badge_info[j.id].point=self.badge_info[j.id].point+h.achieved_counter else local k={}k.name=Tools.StrOfLocalization(j.name)k.desc=Tools.StrOfLocalization(j.desc)k.img="extendRes/badge/"..j.img;k.point=h.achieved_counter;self.badge_info[j.id]=k;table.insert(self.badge_index,j.id)end end end end;if#self.badge_index>0 then table.sort(self.badge_index)end end;function UI_Highlight:RefreshUI()local l=#self.badge_index;if l>5 then l=5 end;self.space.gameObject:SetActive(l==2)for c=1,l do self.badges[c].transform.gameObject:SetActive(true)local i=self.badge_info[self.badge_index[c]]self.badges[c].txt_name.text=i.name;self.badges[c].txt_name.transform:SetSize(l>2 and 160 or 280,73)ImageMgr.SetTextureAsync(self.badges[c].img_icon,i.img)self.badges[c].txt_point.text="+"..i.point;TimeMgr.Delay(0.19+0.06*c,function()self.badges[c].root.gameObject:SetActive(true)end)end end;function UI_Highlight:OpenPopup(m)if not self.badge_index or not self.badge_info or#self.badge_index<m then return end;local i=self.badge_info[self.badge_index[m]]self.popup_info.gameObject:SetActive(true)self.popup_name.text=i.name;ImageMgr.SetTextureAsync(self.popup_icon,i.img)self.popup_desc.text=i.desc end;function UI_Highlight:ClosePopup()if self.locking or not self.popup_info.gameObject.activeSelf then return end;self:SetLocking(true)self.anim_highlight:Play("UI_PopOut")TimeMgr.Delay(0.15,function()self.popup_info.gameObject:SetActive(false)self:SetLocking(false)end)end;function UI_Highlight:NeedShow()local h=DesktopMgr.Inst.badge_info;if h and#h>0 then return true end;return false end;return UI_Highlight